async function handleRunOrderReviewTasks(request, env, db) {
  if (request.method !== "POST") return json({ ok: false, error: "Method Not Allowed" }, 405);
  if (!await requireAdminToken(request, env)) return unauthorized();
  const payload = await request.json().catch(() => ({}));
  const orderNo = String(payload?.orderNo || "").trim();
  const limit = Math.max(1, Math.min(Number.parseInt(String(payload?.limit || "5"), 10) || 5, 20));
  const taskQuery = orderNo ? `SELECT * FROM order_review_tasks WHERE order_no = ? AND status IN ('pending', 'retry') ORDER BY id ASC LIMIT ?` : `SELECT * FROM order_review_tasks WHERE status IN ('pending', 'retry') AND (next_retry_at IS NULL OR next_retry_at <= CURRENT_TIMESTAMP) ORDER BY id ASC LIMIT ?`;
  const taskRows = orderNo ? await db.prepare(taskQuery).bind(orderNo, limit).all() : await db.prepare(taskQuery).bind(limit).all();
  const tasks = taskRows?.results || [];
  const processed = [];
  for (const task of tasks) {
    await db.prepare(`UPDATE order_review_tasks SET status = 'processing', attempts = attempts + 1, updated_at = CURRENT_TIMESTAMP WHERE id = ?`).bind(task.id).run();
    try {
      const order = await db.prepare("SELECT * FROM reward_orders WHERE id = ? LIMIT 1").bind(task.order_id).first();
      if (!order) throw new Error("\u8BA2\u5355\u4E0D\u5B58\u5728");
      const result = await runSingleOrderAutoReview(db, order);
      await db.prepare(
        `UPDATE order_review_tasks SET status = 'completed', result_json = ?, finished_at = CURRENT_TIMESTAMP, updated_at = CURRENT_TIMESTAMP WHERE id = ?`
      ).bind(JSON.stringify(result || {}), task.id).run();
      processed.push({ orderNo: task.order_no, status: "completed", result });
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      await db.prepare(
        `UPDATE order_review_tasks
         SET status = CASE WHEN attempts >= 3 THEN 'failed' ELSE 'retry' END,
             last_error = ?, next_retry_at = datetime('now', '+5 minutes'), updated_at = CURRENT_TIMESTAMP
         WHERE id = ?`
      ).bind(message, task.id).run();
      processed.push({ orderNo: task.order_no, status: "failed", error: message });
    }
  }
  return json({ ok: true, processedCount: processed.length, processed });
}
